def calculate_expression(expr: str) -> float:
    """
    Evaluate a simple arithmetic expression and return the result.

    Parameters:
        expr (str): A string representing a mathematical expression (e.g., '1+1', '2*3-4')

    Returns:
        float: The result of the evaluated expression

    Raises:
        ValueError: If the expression is invalid or cannot be parsed
    """
    try:
        # Parse the expression using basic operators
        # This is a simplified parser for demonstration purposes
        # In a real system, you'd want to use a proper parser like `ast`
        if '+' in expr:
            parts = expr.split('+')
            if len(parts) == 2:
                return float(parts[0]) + float(parts[1])
        elif '-' in expr:
            parts = expr.split('-')
            if len(parts) == 2:
                return float(parts[0]) - float(parts[1])
        elif '*' in expr:
            parts = expr.split('*')
            if len(parts) == 2:
                return float(parts[0]) * float(parts[1])
        elif '/' in expr:
            parts = expr.split('/')
            if len(parts) == 2:
                numerator = float(parts[0])
                denominator = float(parts[1])
                if denominator == 0:
                    raise ValueError("Division by zero")
                return numerator / denominator
        elif '**' in expr or '^' in expr:
            parts = expr.split('**') if '**' in expr else expr.split('^')
            if len(parts) == 2:
                return float(parts[0]) ** float(parts[1])

        raise ValueError(f"Unsupported operation in expression: {expr}")

    except ValueError as e:
        raise ValueError(f"Invalid expression: {expr}. Error: {str(e)}")

# User requested: calculate 1+1
result = calculate_expression('1+1')
print(f"1 + 1 = {result}")
